172: LLVM_ABI void reportVectorizationFailure(
173:     const StringRef DebugMsg, const StringRef OREMsg, const StringRef ORETag,
174:     OptimizationRemarkEmitter *ORE, Loop *TheLoop, Instruction *I = nullptr);
